INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0001-0000-0000-000000000000', 'acc02b01-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Welcome to the surveying lab</h3><p>SRVY 1335 is the hands-on companion to the lecture course SRVY 1341. In lab you will physically set up and operate <strong>total stations, theodolites, levels, and EDM equipment</strong>, run real traverses and level loops, set monuments, and reduce your own field data. Before any instrument leaves the cage, you must understand two things: how to stay safe, and how to keep a defensible record of what you measured. This first lab establishes both habits.</p><p>Field surveying happens in active environments &mdash; roadway shoulders, construction sites, brush, and open sun. The most common injuries in this profession are not exotic; they are being struck by vehicles, heat illness, falls on uneven ground, and contact with utilities. Treat every setup as a small job-hazard analysis: scan for traffic, overhead power, trip hazards, and weather before you plant the tripod.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0001-0000-0000-000000000001', 'acc02b01-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Never turn your back to live traffic. Use a high-visibility (ANSI Class 2/3) vest, cones, and a spotter when occupying a point near a roadway. In a work zone, a Texas MUTCD-compliant traffic control plan is required."}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0001-0000-0000-000000000002', 'acc02b01-0000-0000-0000-000000000001', 'table', '{"headers":["Item","Purpose","Pre-use check"],"rows":[["Total station + tribrach","Angles + distances","Optical plummet, level vials, battery"],["Tripod","Stable instrument support","Tighten leg clamps, check head plate"],["Prism + pole","EDM target","Bubble on pole, prism offset value"],["Automatic/digital level","Differential leveling","Compensator free, vial level"],["Level rod","Read elevations","Sections seated, rod bubble"],["Field book + pen","Permanent record","Ink, gridded, your name inside cover"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0001-0000-0000-000000000003', 'acc02b01-0000-0000-0000-000000000001', 'text', '{"html":"<h3>The field book as a legal record</h3><p>Your field book is not scratch paper &mdash; it is the <strong>original observed record</strong> of the survey and can be subpoenaed. Follow standard conventions: write in <strong>waterproof ink</strong>; put your name, the project, the date, the crew, the instrument serial number, and the weather at the top of each day&rsquo;s notes. Numerical observations go in tabular columns on the <strong>right-hand (ruled) page</strong>; a north-arrowed <strong>sketch</strong> goes on the left-hand (grid) page. <strong>Never erase.</strong> If a value is wrong, draw a single line through it, initial it, and write the corrected value beside it so the original remains legible. Number your pages and never tear one out.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0001-0000-0000-000000000004', 'acc02b01-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Texas Administrative Code (22 TAC Ch. 663) and the Texas Board of Professional Land Surveying require surveyors to maintain the records supporting a survey, including original field notes, for the statutory retention period."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0001-0000-0000-000000000005', 'acc02b01-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Run a quick job-hazard scan (traffic, heat, utilities, terrain) at every setup.","Inventory and inspect every instrument at check-out and check-in.","Keep field notes in ink with right-page data, left-page sketch, no erasures.","Original field notes are part of the legal survey record in Texas."]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0002-0000-0000-000000000000', 'acc02b02-0000-0000-0000-000000000001', 'text', '{"html":"<h3>How an EDM measures distance</h3><p>An <strong>electronic distance meter (EDM)</strong> sends a modulated infrared or laser beam to a reflector (prism) and analyzes the returning signal. The dominant method in survey instruments is <strong>phase comparison</strong>: the instrument compares the phase of the outgoing modulation to the returning signal to measure the fractional part of a wavelength, then uses several modulation frequencies to count the whole number of wavelengths over the path. Because the light travels out and back, the path is twice the distance, so the instrument divides by two internally. Modern reflectorless and pulse instruments instead time the round-trip travel of a pulse (time-of-flight).</p><p>The raw quantity an EDM reports is a <strong>slope distance</strong> along the line of sight between the instrument&rsquo;s electrical center and the prism. To use it on a map or in a traverse, you must correct it and then reduce it to horizontal.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0002-0000-0000-000000000001', 'acc02b02-0000-0000-0000-000000000001', 'equation', '{"latex":"D = \\frac{c}{2 n f}\\left(N + \\frac{\\Delta\\varphi}{2\\pi}\\right)","label":"Phase-comparison distance (N whole wavelengths + phase fraction)","display":"block"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0002-0000-0000-000000000002', 'acc02b02-0000-0000-0000-000000000001', 'text', '{"html":"<h3>The three corrections</h3><p>Three systematic corrections turn a raw EDM reading into a usable distance. (1) The <strong>reflector / prism constant</strong> accounts for the offset between the prism&rsquo;s optical center and the point being measured; a typical glass prism offset is &minus;30 mm or 0 mm depending on type, and the wrong value biases every distance by that constant. (2) The <strong>atmospheric (ppm) correction</strong> adjusts for the actual speed of light, which depends on air temperature and barometric pressure; a rule of thumb is roughly 1 ppm per 1&deg;C or per a few millibars. (3) The <strong>instrument additive constant</strong>, found by baseline calibration, accounts for the offset of the EDM&rsquo;s electrical center. Enter the prism constant and ppm in the data collector before measuring.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0002-0000-0000-000000000003', 'acc02b02-0000-0000-0000-000000000001', 'table', '{"headers":["Correction","Cause","Typical effect"],"rows":[["Prism constant","Optical center offset of reflector","Fixed mm bias on every shot"],["Atmospheric ppm","Speed of light vs temp/pressure","~1 ppm per deg C; scales with distance"],["Slope-to-horizontal","Line of sight not level","H = S sin(zenith)"]]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0002-0000-0000-000000000004', 'acc02b02-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"A wrong prism constant is the most common EDM blunder. A 360-deg prism, a mini-prism, and a standard prism can have different constants. Confirm the constant matches the physical prism you are using on the pole."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0002-0000-0000-000000000005', 'acc02b02-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["EDM reports slope distance; you must correct and then reduce to horizontal.","Always set the correct prism constant and atmospheric ppm in the field.","Horizontal distance = slope x sin(zenith) = slope x cos(vertical angle).","Calibrate against a known baseline to recover the instrument additive constant."]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0003-0000-0000-000000000000', 'acc02b03-0000-0000-0000-000000000001', 'text', '{"html":"<h3>What a total station does</h3><p>A <strong>total station</strong> combines an <strong>electronic theodolite</strong> (which reads horizontal and vertical/zenith angles digitally) with a built-in <strong>EDM</strong> and a microprocessor. For each pointing it captures a <strong>horizontal angle (HA)</strong>, a <strong>zenith angle (ZA)</strong>, and a <strong>slope distance (SD)</strong>, then computes horizontal distance, elevation difference, and northing/easting on the fly. Because it does the trigonometry internally, the field crew can stake and locate points directly in coordinates &mdash; but only after the instrument is correctly set up and oriented.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0003-0000-0000-000000000001', 'acc02b03-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Setup procedure (centering and leveling)</h3><p>Setup is an iterative dance between centering over the point and leveling the instrument:</p><ul><li>Spread the tripod so the head is roughly over the point and near level; press the legs firmly into the ground.</li><li>Turn on the laser/optical plummet and shift the tripod (or slide on the head) until the plummet is near the point.</li><li>Use the <strong>foot screws</strong> to center the circular (bull&rsquo;s-eye) bubble.</li><li>Use the <strong>plate level</strong>: rotate 90&deg; between adjustments, leveling with two foot screws then the third.</li><li>Re-check the plummet; loosen the tribrach and <strong>shift</strong> the instrument to fine-center over the point.</li><li>Re-level and re-check. Iterate until both the bubble and the plummet hold simultaneously.</li></ul>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0003-0000-0000-000000000002', 'acc02b03-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Check the optical/laser plummet adjustment periodically: with the instrument leveled over a marked point, rotate 180 deg in HA. If the plummet drifts off the mark, it is out of adjustment and you have been centering over a circle, not a point."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0003-0000-0000-000000000003', 'acc02b03-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Orientation by backsight</h3><p>A leveled instrument still has an arbitrary horizontal circle until you <strong>orient</strong> it. Occupy a point of known coordinates, enter its coordinates and instrument height, then <strong>backsight</strong> a second known point (or a known azimuth) and set the horizontal circle to the computed backsight bearing/azimuth. From that moment, every foresight HA is in the project frame and the total station can compute coordinates for new points. Always take a check shot to a third known point to confirm the orientation before collecting data.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0003-0000-0000-000000000004', 'acc02b03-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Center and level iteratively until plummet and bubble hold together.","A total station records HA, ZA, SD and reduces to coordinates internally.","Orient by occupying a known point and backsighting a known point/azimuth.","Always take an independent check shot before collecting production data."]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0004-0000-0000-000000000000', 'acc02b04-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Anatomy of a theodolite</h3><p>A <strong>theodolite</strong> is a precision angle-measuring instrument. Its telescope rotates about the horizontal <strong>trunnion axis</strong>; the whole upper body (alidade) rotates about the vertical <strong>standing axis</strong>; and the <strong>line of sight (collimation axis)</strong> runs through the telescope. For correct angles these three axes must satisfy adjustment relationships: the standing axis truly vertical, the trunnion axis perpendicular to it, and the line of sight perpendicular to the trunnion axis. Optical-reading theodolites display the circles through a microscope; digital theodolites read them electronically &mdash; the same as the angle engine inside a total station.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0004-0000-0000-000000000001', 'acc02b04-0000-0000-0000-000000000001', 'table', '{"headers":["Axis","Should be","Error if not"],"rows":[["Standing (vertical) axis","Truly vertical","Not removable by face reversal"],["Trunnion (horizontal) axis","Perp. to standing axis","Horizontal-axis error"],["Line of sight (collimation)","Perp. to trunnion axis","Collimation error"],["Vertical circle index","Reads 90 deg level","Vertical-index error"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0004-0000-0000-000000000002', 'acc02b04-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Direct and reverse (two faces)</h3><p>The most important field technique is measuring each angle in <strong>both faces</strong>. In <strong>face left (direct)</strong> the vertical circle is on the observer&rsquo;s left; in <strong>face right (reverse)</strong> the telescope is plunged and the body turned 180&deg;. Reading the same angle in both faces and meaning the results <strong>cancels</strong> collimation error, horizontal-axis error, and vertical-circle index error, because those errors change sign between faces. The procedure for one set: backsight FL and read, foresight FL and read, plunge, foresight FR and read, backsight FR and read. The meaned horizontal angle is far more reliable than a single pointing.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0004-0000-0000-000000000003', 'acc02b04-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Errors that reverse sign between faces (collimation, trunnion-axis, vertical-index) are removed by meaning direct and reverse. Standing-axis (plate not level) error does NOT reverse, so level carefully."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0004-0000-0000-000000000004', 'acc02b04-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Three axes must be mutually perpendicular for correct angles.","Measure each angle face-left and face-right and mean them.","Meaning faces cancels collimation, horizontal-axis, and vertical-index errors.","Standing-axis (un-level) error is not cancelled by faces — level precisely."]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0005-0000-0000-000000000000', 'acc02b05-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Why we repeat angles</h3><p>A single pointing carries random pointing and reading error. To beat it down we either <strong>repeat</strong> the angle or take several <strong>direction sets</strong>. In the <strong>repetition method</strong>, the angle is turned and accumulated <em>n</em> times on the circle, then the total is divided by <em>n</em>; this effectively divides the circle&rsquo;s reading resolution by <em>n</em> and averages the pointing error. In the <strong>direction method</strong>, you zero on a reference, then read the direction to each target; the angle is a difference of directions, and several sets are meaned. Both should be done in both faces.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0005-0000-0000-000000000001', 'acc02b05-0000-0000-0000-000000000001', 'equation', '{"latex":"\\sigma = \\sqrt{\\dfrac{\\sum (x_i - \\bar{x})^2}{n-1}}","label":"Sample standard deviation of a set of angle readings","display":"block"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0005-0000-0000-000000000002', 'acc02b05-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Reducing a set and the closure check</h3><p>For each set, compute the mean angle, the <strong>range (spread)</strong> between the largest and smallest, and the sample standard deviation. A tight spread (a few seconds for a 5&Prime; instrument) confirms good work; a wild value flags a blunder to re-observe. When the angles form a <strong>closed polygon</strong>, the interior angles must satisfy a geometric condition: their sum equals <strong>(n &minus; 2) &times; 180&deg;</strong>. The amount by which the measured sum departs from that theoretical sum is the <strong>angular misclosure</strong>, which is distributed back into the angles (usually equally) before computing bearings.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0005-0000-0000-000000000003', 'acc02b05-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Example specification: maximum angular misclosure = 30 seconds x sqrt(n) for a low-order traverse with n angles. A 6-sided traverse would allow about 73 seconds of misclosure."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0005-0000-0000-000000000004', 'acc02b05-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Repetition divides reading resolution by the number of turnings.","Report mean, spread, and standard deviation for every angle set.","Interior angles of a closed n-gon sum to (n-2) x 180 deg.","Angular misclosure is the measured sum minus the theoretical sum."]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0006-0000-0000-000000000000', 'acc02b06-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Vertical angle vs. zenith angle</h3><p>Two conventions describe how far the line of sight tilts. A <strong>vertical angle</strong> is measured up (+) or down (&minus;) from the <strong>horizontal</strong>. A <strong>zenith angle</strong> is measured from the <strong>upward vertical</strong>: 0&deg; points straight up, <strong>90&deg; is horizontal</strong>, and 180&deg; points straight down. Most modern total stations report the zenith angle. They are simply related: <em>vertical angle = 90&deg; &minus; zenith angle</em>. Knowing which your instrument reports is essential, because the reduction formulas use the angle directly.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0006-0000-0000-000000000001', 'acc02b06-0000-0000-0000-000000000001', 'equation', '{"latex":"H = S\\,\\sin(z), \\qquad V = S\\,\\cos(z)","label":"Horizontal (H) and vertical (V) from slope distance S and zenith angle z","display":"block"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0006-0000-0000-000000000002', 'acc02b06-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Trigonometric leveling</h3><p>A total station can determine an elevation difference without a level, using the zenith angle and slope distance &mdash; this is <strong>trigonometric leveling</strong>. The vertical component of the shot is <em>V = S cos(z)</em>. But the line of sight starts at the instrument&rsquo;s optical center (height <strong>HI</strong> above the occupied point) and ends at the prism (height <strong>HR</strong> above the target point). So the elevation difference between the two ground points is:</p><p><em>&Delta;Elev = V + HI &minus; HR</em></p><p>For long sights, refined work also adds a combined <strong>earth-curvature and refraction</strong> correction, but for typical lab distances it is negligible. Always observe the zenith angle in both faces and mean to remove vertical-index error.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0006-0000-0000-000000000003', 'acc02b06-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"A frequent blunder is forgetting HI and HR. If you only add V to the occupied elevation, your foresight elevation is wrong by (HI - HR). Record both heights every setup."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0006-0000-0000-000000000004', 'acc02b06-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Zenith angle: 0 deg up, 90 deg horizontal, 180 deg down.","H = S sin(z), V = S cos(z) using the zenith angle z.","Trig leveling: delta-elevation = V + HI - HR.","Mean both faces to remove vertical-circle index error."]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0007-0000-0000-000000000000', 'acc02b07-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Good taping technique</h3><p>Even in the EDM era, taping is a required skill for short ties, layout, and checks. Good chaining demands: <strong>horizontal alignment</strong> (the head chainer aligned by the rear chainer or instrument), <strong>plumbing</strong> the tape ends over the points with a plumb bob when the tape is held off the ground, applying a <strong>standard tension</strong> (commonly 10&ndash;20 lb) with a tension handle, and keeping the tape <strong>fully supported</strong> or correcting for sag if it is suspended. On slopes, you either measure horizontally in steps (<strong>breaking chain</strong>) or measure along the slope and reduce.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0007-0000-0000-000000000001', 'acc02b07-0000-0000-0000-000000000001', 'table', '{"headers":["Correction","Formula (per length L)","Sign rule"],"rows":[["Temperature","C_t = k (T - T0) L","+ if hotter than standard"],["Pull / tension","C_p = (P - P0) L / (A E)","+ if pulled harder"],["Sag","C_s = - w^2 L^3 / (24 P^2)","always shortens (negative)"],["Slope","H = L cos(alpha)","horizontal < slope length"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0007-0000-0000-000000000002', 'acc02b07-0000-0000-0000-000000000001', 'equation', '{"latex":"H = L\\cos\\alpha \\;\\approx\\; L - \\dfrac{h^2}{2L}","label":"Slope reduction: horizontal H from slope length L, slope angle alpha, elevation diff h","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0007-0000-0000-000000000003', 'acc02b07-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Comparing taping to EDM</h3><p>A central lab exercise is to measure the same line by tape and by EDM and reconcile them. Tape the line with all corrections applied; measure it with the total station (correct prism constant and ppm) and reduce the slope distance to horizontal. Over a short, well-controlled course the two should agree to within a few hundredths of a foot. A persistent difference points to a systematic error &mdash; an uncorrected slope, a wrong prism constant, a temperature correction omitted, or a mis-identified point. Investigating the disagreement is how surveyors find blunders.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0007-0000-0000-000000000004', 'acc02b07-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Sign check: if the tape is hotter than its standard temperature it is longer than nominal, so it reads too SHORT a distance, and the correction is positive (add)."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0007-0000-0000-000000000005', 'acc02b07-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Tape with alignment, plumbing, standard tension, and support/sag control.","Apply temperature, pull, sag, and slope corrections with correct signs.","Reduce slope length to horizontal with H = L cos(slope angle).","Tape and EDM should agree within hundredths; investigate larger gaps."]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0008-0000-0000-000000000000', 'acc02b08-0000-0000-0000-000000000001', 'text', '{"html":"<h3>What the practical exam covers</h3><p>The midterm is a <strong>timed, hands-on station</strong> that assesses the core skills from Weeks 1&ndash;7. Expect to: set up and level a total station over a marked point within a stated centering and leveling tolerance; orient by occupying a known point and backsighting a known reference; take a <strong>check shot</strong> to confirm orientation; measure a horizontal angle in <strong>direct and reverse</strong> and mean it; measure a distance and reduce the slope distance to horizontal; and record everything cleanly in your field book. You are graded on <em>procedure, accuracy, and documentation</em>.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0008-0000-0000-000000000001', 'acc02b08-0000-0000-0000-000000000001', 'table', '{"headers":["Station task","What is graded","Typical tolerance"],"rows":[["Setup","Centering + leveling","Plumb within ~2 mm; bubble centered"],["Orientation","Correct backsight azimuth","Check shot within a few hundredths"],["Angle (D/R)","Mean angle + spread","FL/FR agree within instrument spec"],["Distance","Slope reduced to horizontal","Agrees with control within tolerance"],["Field book","Legible, complete, dated","No erasures, header complete"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0008-0000-0000-000000000002', 'acc02b08-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Do not rush the setup to save time. A poorly leveled or off-center instrument biases every observation and is the most common cause of a failed practical. Iterate centering and leveling until both hold."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0008-0000-0000-000000000003', 'acc02b08-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Reduction under exam conditions</h3><p>Bring and use the reduction skills cold: mean the direct/reverse angle, convert a zenith angle and slope distance to horizontal and vertical components, and compute a trig elevation with HI and HR. Show your work step by step in the field book so a grader can follow your logic even if a single arithmetic slip occurs. A clean header (name, date, instrument, weather), tabular observations on the right, and a labeled sketch on the left demonstrate professional habits the exam rewards.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0008-0000-0000-000000000004', 'acc02b08-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Setup, orient, and verify with a check shot before measuring.","Measure angles in both faces and mean; reduce distances to horizontal.","You are graded on procedure and documentation, not only the answer.","Methodical pace prevents the skipped-step blunders that fail practicals."]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0009-0000-0000-000000000000', 'acc02b09-0000-0000-0000-000000000001', 'text', '{"html":"<h3>What an open traverse is</h3><p>An <strong>open traverse</strong> is a connected series of courses that begins at a point of known position and proceeds to a terminal point whose position is <em>not</em> independently known. It is common on <strong>route surveys</strong> &mdash; highways, pipelines, transmission lines &mdash; where the survey naturally moves forward and never returns to the start. The crew occupies a station, backsights the previous station to orient, turns the angle to the next station, and measures the distance, then moves up. Coordinates are computed by propagating azimuths and applying latitudes and departures.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0009-0000-0000-000000000001', 'acc02b09-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Propagating azimuths</h3><p>Each new course direction comes from the previous one plus the measured angle. If you record <strong>deflection angles</strong>, the forward azimuth of the next course is the previous azimuth plus the right deflection (or minus a left deflection). If you record <strong>interior/clockwise angles to the right</strong>, the next azimuth is the back azimuth of the previous course plus the angle. Either way, after each addition you normalize the result into the 0&deg;&ndash;360&deg; range. Getting the bookkeeping right is the heart of traverse computation.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0009-0000-0000-000000000002', 'acc02b09-0000-0000-0000-000000000001', 'equation', '{"latex":"Az_{i+1} = (Az_i + 180^\\circ + \\theta_i) \\bmod 360^\\circ","label":"Forward azimuth from back azimuth plus the measured angle-right","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0009-0000-0000-000000000003', 'acc02b09-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"An open traverse provides NO closure check. A single undetected blunder propagates to every downstream point. Build in redundancy: double the angles, repeat distances, and tie into independent control whenever possible."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0009-0000-0000-000000000004', 'acc02b09-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Open traverse: known start, unknown end, no closure check.","Occupy, backsight, turn angle, measure distance, advance.","Propagate azimuths by adding the measured angle and normalizing.","Add redundancy because errors cannot self-detect in an open traverse."]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0010-0000-0000-000000000000', 'acc02b10-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Why closed traverses are preferred</h3><p>A <strong>closed traverse</strong> either returns to its starting station (a <strong>closed-loop</strong> traverse) or runs between two stations of known coordinates (a <strong>closed-connecting / link</strong> traverse). Either way it imposes a <strong>geometric condition</strong> that lets you compute how far off the field work is &mdash; the <strong>misclosure</strong> &mdash; and then adjust it. Boundary surveys are virtually always closed so the legal description mathematically closes. The field procedure is the same station-to-station routine as an open traverse, but the loop lets you check yourself.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0010-0000-0000-000000000001', 'acc02b10-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Computing misclosure</h3><p>After balancing the angles, compute each course&rsquo;s <strong>latitude</strong> (north&ndash;south, <em>L cos(azimuth)</em>) and <strong>departure</strong> (east&ndash;west, <em>L sin(azimuth)</em>). For a loop, the latitudes should sum to zero and the departures should sum to zero. The leftover sums are the <strong>closure in latitude</strong> and <strong>closure in departure</strong>. The <strong>linear misclosure</strong> is the straight-line distance these represent:</p><p><em>misclosure = hypot(&Sigma;Lat, &Sigma;Dep)</em></p><p>Dividing the total course length by the misclosure gives the <strong>precision ratio</strong> 1:N &mdash; the higher N, the better.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0010-0000-0000-000000000002', 'acc02b10-0000-0000-0000-000000000001', 'equation', '{"latex":"e = \\sqrt{(\\textstyle\\sum \\text{Lat})^2 + (\\textstyle\\sum \\text{Dep})^2}, \\qquad \\text{precision} = \\dfrac{\\sum L}{e}","label":"Linear misclosure e and precision ratio","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0010-0000-0000-000000000003', 'acc02b10-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Adjusting by the compass rule</h3><p>If the precision meets the project specification, distribute the closures by the <strong>compass (Bowditch) rule</strong>: each course&rsquo;s correction to its latitude (or departure) is proportional to its length over the total length. After correcting all courses, the adjusted latitudes and departures sum to zero, and you compute final adjusted coordinates for every station. This balanced traverse is what feeds area computation and the final drawing.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0010-0000-0000-000000000004', 'acc02b10-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Compass-rule correction to a course latitude = -(sum of latitudes) x (course length / total length). The departure correction follows the same proportion."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0010-0000-0000-000000000005', 'acc02b10-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Closed traverses self-check via misclosure; loops should sum lat and dep to zero.","Linear misclosure = hypot(sum of latitudes, sum of departures).","Precision ratio = total length / misclosure, written 1:N.","Compass (Bowditch) rule distributes closure in proportion to course length."]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0011-0000-0000-000000000000', 'acc02b11-0000-0000-0000-000000000001', 'text', '{"html":"<h3>From field book to data collector</h3><p>Modern crews record observations in an electronic <strong>data collector</strong> (handheld or the instrument&rsquo;s onboard software). Each measured point is stored with a <strong>point number</strong>, its reduced <strong>northing/easting/elevation</strong>, and a <strong>feature code</strong> describing what it is (e.g., EP for edge of pavement, FH for fire hydrant). Storing the <strong>raw</strong> observations (HA/ZA/SD, HI, HR, backsight) as well as coordinates lets the office re-reduce the data if a setup value was wrong. Electronic recording removes the transcription errors that creep into hand-kept notes.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0011-0000-0000-000000000001', 'acc02b11-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Field-to-finish coding</h3><p><strong>Field-to-finish</strong> is the practice of coding points in the field so the office CAD software draws the map automatically. A controlled <strong>code list</strong> maps each descriptor to a layer, symbol, and linework behavior. Line codes carry control characters &mdash; begin line, continue, close figure, start a curve &mdash; so a string of curb shots becomes a polyline without manual drafting. Discipline matters: a single mistyped code or a skipped &ldquo;begin line&rdquo; produces tangled linework that takes longer to fix than it saved.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0011-0000-0000-000000000002', 'acc02b11-0000-0000-0000-000000000001', 'table', '{"headers":["File type","Contents","Why keep it"],"rows":[["Raw (.raw/.rw5)","Observed HA/ZA/SD, HI, HR, setups","Re-reduce if a setup value was wrong"],["Coordinate (.csv/.txt)","Point #, N, E, Z, code","Feeds CAD and stakeout"],["Code list","Descriptor to layer/symbol map","Drives field-to-finish drafting"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0011-0000-0000-000000000003', 'acc02b11-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Never delete the raw data file. If a prism constant, instrument height, or backsight was entered wrong, only the raw file lets you correct the entire dataset. Back up to a second card or the cloud before leaving the site."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0011-0000-0000-000000000004', 'acc02b11-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Data collectors store raw observations plus reduced coordinates and codes.","Feature codes drive automatic field-to-finish linework in CAD.","Use consistent point numbering and a controlled code list.","Preserve and back up the raw file before leaving the field."]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0012-0000-0000-000000000000', 'acc02b12-0000-0000-0000-000000000001', 'text', '{"html":"<h3>How differential leveling works</h3><p><strong>Differential leveling</strong> carries an elevation from a point of known elevation (a <strong>benchmark</strong>, BM) to new points using a level and a graduated rod. With the level set midway, the crew takes a <strong>backsight (BS)</strong> &mdash; a rod reading on the known point &mdash; then a <strong>foresight (FS)</strong> on the next point. When the next point is just a temporary stepping stone, it is a <strong>turning point (TP)</strong>. By leap-frogging level and rod, elevation is transferred any distance and over any terrain.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0012-0000-0000-000000000001', 'acc02b12-0000-0000-0000-000000000001', 'equation', '{"latex":"HI = Elev_{BM} + BS, \\qquad Elev_{new} = HI - FS","label":"Height-of-instrument (HI) reduction","display":"block"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0012-0000-0000-000000000002', 'acc02b12-0000-0000-0000-000000000001', 'table', '{"headers":["Station","BS (+)","HI","FS (-)","Elevation"],"rows":[["BM-1","4.21","104.21","","100.00"],["TP-1","5.07","106.62","2.66","101.55"],["BM-2","","","3.18","103.44"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0012-0000-0000-000000000003', 'acc02b12-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Checks: misclosure and balanced sights</h3><p>Two checks protect a level run. First, the <strong>page/arithmetic check</strong>: the sum of backsights minus the sum of foresights equals the net elevation change (last elevation minus first). Second, the <strong>loop misclosure</strong>: running back to the starting benchmark (or to a second known BM) should reproduce its elevation; the small leftover is the misclosure, which is distributed among the setups if within tolerance. In the field, <strong>balance the BS and FS distances</strong> at each setup &mdash; equal sight lengths cancel instrumental collimation error and earth curvature/refraction.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0012-0000-0000-000000000004', 'acc02b12-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Allowable loop misclosure is often written C x sqrt(M) or C x sqrt(K), where M is miles (or K kilometers) of leveling and C is an order-of-survey constant (e.g., 0.02 ft x sqrt(miles))."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0012-0000-0000-000000000005', 'acc02b12-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["HI = elevation + backsight; new elevation = HI - foresight.","Turning points carry elevation between benchmarks.","Sum BS - sum FS must equal the net elevation change (arithmetic check).","Balance BS/FS distances to cancel collimation and curvature/refraction."]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0013-0000-0000-000000000000', 'acc02b13-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Monuments and corners</h3><p>A <strong>corner</strong> is a point of legal significance on a boundary; a <strong>monument</strong> is the physical object that marks it &mdash; an iron rod, pipe, capped rebar, concrete monument, or a natural/structural object called out in the record. The value of a monument comes from <strong>permanence</strong> and a <strong>documented record</strong> of how, when, and by whom it was set, and how it ties to surrounding evidence. Setting monuments and corner establishment are core deliverables of a boundary survey and are explicitly named in the SRVY 1335 course content.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0013-0000-0000-000000000001', 'acc02b13-0000-0000-0000-000000000001', 'table', '{"headers":["Monument type","Typical use","Note"],"rows":[["Capped iron rod / rebar","Most modern property corners","Cap stamped with RPLS/firm no."],["Iron pipe","Older corners","Often found, rarely newly set"],["Concrete monument","Control / major corners","Very durable, surveyed disk"],["Witness / reference mark","Tie when corner can''t be set","Recorded offset to true corner"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0013-0000-0000-000000000002', 'acc02b13-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Texas differs: under the Professional Land Surveying Practices Act and 22 TAC Ch. 663, monuments set to mark a property corner must be capped/identified with the responsible RPLS''s registration or firm number. Setting boundary monuments is the practice of professional surveying — students do so only under RPLS supervision."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0013-0000-0000-000000000003', 'acc02b13-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Reference ties and perpetuation</h3><p>Because a monument can be destroyed by construction or weather, the surveyor records <strong>reference (witness) ties</strong> &mdash; measured distances and bearings from the corner to several nearby permanent objects &mdash; so it can be re-set in the same spot later. When you encounter an <strong>original monument</strong> (one set by the surveyor who created the boundary), the rule of boundary law is to <strong>recover and honor it</strong>, not to set a new corner by measurement: an undisturbed original monument controls over distances and bearings. Document the recovery thoroughly &mdash; that record perpetuates the corner.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0013-0000-0000-000000000004', 'acc02b13-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["A monument''s legal value comes from permanence plus a documented record.","Texas requires set property-corner monuments to be capped with the RPLS/firm number.","Record reference (witness) ties so a disturbed corner can be re-set.","Recover and honor original monuments — they control over measurements."]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0014-0000-0000-000000000000', 'acc02b14-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Profile leveling</h3><p><strong>Profile leveling</strong> measures the elevation of the ground along a line &mdash; a road centerline, a sewer alignment, a ditch &mdash; at regular <strong>stations</strong> (e.g., every 50 or 100 ft, written 0+00, 1+00, ...). It uses the same level and HI method as differential leveling, but adds many <strong>intermediate foresights (IFS)</strong>: ground-rod shots taken from the current HI that record elevation but do <em>not</em> advance the instrument. Only true <strong>turning points</strong> carry the HI forward when the instrument must move. The result is a <strong>profile</strong> &mdash; a side view of the ground along the line.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0014-0000-0000-000000000001', 'acc02b14-0000-0000-0000-000000000001', 'equation', '{"latex":"Elev_{station} = HI - IFS","label":"Intermediate ground elevation from the height of instrument","display":"block"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0014-0000-0000-000000000002', 'acc02b14-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Cross-sections and earthwork</h3><p>A <strong>cross-section</strong> is a profile taken <em>perpendicular</em> to the centerline at a station, capturing ground elevation at measured <strong>offsets</strong> left and right (e.g., &minus;25, &minus;10, 0, +10, +25 ft). Cross-sections describe the shape of the ground across the corridor and are the basis for earthwork volumes. Comparing each measured ground elevation to the <strong>design grade</strong> elevation at that point gives a <strong>cut</strong> (ground above grade, must be removed) or a <strong>fill</strong> (ground below grade, must be added). Plotted profiles and cross-sections, with stationing along the bottom, are standard construction deliverables.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0014-0000-0000-000000000003', 'acc02b14-0000-0000-0000-000000000001', 'table', '{"headers":["Offset (ft)","Ground elev","Grade elev","Cut(+)/Fill(-)"],"rows":[["-25","101.8","100.0","+1.8 cut"],["0 (CL)","100.4","100.0","+0.4 cut"],["+25","99.1","100.0","-0.9 fill"]]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0014-0000-0000-000000000004', 'acc02b14-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Stationing convention: 1+00 means 100 ft from the start (0+00). A point at 3+50 is 350 ft along the centerline. Offsets are measured perpendicular, negative left and positive right (facing increasing stations)."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0014-0000-0000-000000000005', 'acc02b14-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Profile leveling records ground elevation at stations along a centerline.","Intermediate foresights (HI - IFS) record ground but don''t advance the HI.","Cross-sections record elevation at offsets perpendicular to the centerline.","Cut = ground above grade; fill = ground below grade."]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0015-0000-0000-000000000000', 'acc02b15-0000-0000-0000-000000000001', 'text', '{"html":"<h3>The capstone project</h3><p>The comprehensive project is the lab&rsquo;s capstone: a complete small survey that exercises every skill from the semester. A typical scope is to establish <strong>control</strong> over a site, run and adjust a <strong>closed traverse</strong>, transfer <strong>vertical control</strong> by leveling, collect <strong>topographic detail</strong>, reduce and adjust the data, compute the <strong>area</strong> of the bounded parcel, and deliver a finished, checked <strong>drawing</strong>. You work as a crew, rotate roles (instrument operator, rodperson, note keeper), and are graded on the end-to-end product, not just one task.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0015-0000-0000-000000000001', 'acc02b15-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Sequence of work</h3><p>Order matters. Establish control first &mdash; an out-of-spec control traverse poisons everything built on it:</p><ul><li>Reconnoiter the site and plan station locations with good intervisibility.</li><li>Run the closed traverse (angles in both faces, distances measured both ways) and check angular and linear misclosure against the spec.</li><li>Adjust the traverse (compass rule) and compute final coordinates.</li><li>Carry vertical control by differential leveling to the project benchmarks.</li><li>Collect topographic detail by radial shots from control, each with a feature code.</li><li>Reduce, draft field-to-finish, and compute area by coordinates.</li></ul>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0015-0000-0000-000000000002', 'acc02b15-0000-0000-0000-000000000001', 'callout', '{"type":"warning","text":"Do not collect topo before your control traverse closes and is adjusted. Detail shots inherit the error of the setup they are taken from; bad control means redrawing everything."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0015-0000-0000-000000000003', 'acc02b15-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Deliverable and QA/QC</h3><p>The deliverable is a clean drawing with the boundary, topographic features, contours or spot elevations, control table, north arrow, scale, and computed area &mdash; plus the supporting field notes and reduced coordinate file. Before submitting, run <strong>QA/QC</strong>: confirm the traverse precision meets spec; spot-check several coordinates by independent computation; verify linework connects correctly with no stray segments; and confirm the parcel <strong>area</strong> by a second method (e.g., coordinate area vs. a CAD area readout). A surveyor signs nothing they have not checked.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0015-0000-0000-000000000004', 'acc02b15-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["Capstone integrates control, leveling, topo, reduction, adjustment, area, and drafting.","Establish and adjust control before collecting any detail.","Collect topo by coded radial shots for field-to-finish drafting.","QA/QC: verify closure, coordinates, linework, and area before delivering."]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0016-0000-0000-000000000000', 'acc02b16-0000-0000-0000-000000000001', 'text', '{"html":"<h3>The final practical</h3><p>The final practical is a <strong>comprehensive, independent</strong> exercise. Working alone or with minimal crew, you will set up and orient an instrument, observe a short <strong>closed traverse</strong> (angles in both faces, distances), and reduce the data to <strong>coordinates</strong>, <strong>misclosure</strong>, a <strong>precision ratio</strong>, and a computed <strong>area</strong>. It rolls together every competency: setup, angles, distances, leveling concepts, reduction, adjustment, and area computation &mdash; under time pressure and graded on procedure and documentation as much as on the answers.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0016-0000-0000-000000000001', 'acc02b16-0000-0000-0000-000000000001', 'table', '{"headers":["Phase","Task","Deliverable"],"rows":[["Field","Setup, orient, check shot","Verified orientation"],["Field","Observe closed traverse (D/R)","Balanced angles"],["Office","Latitudes/departures, misclosure","Precision ratio 1:N"],["Office","Adjust + coordinates","Adjusted station coords"],["Office","Area by coordinates","Parcel area + check"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0016-0000-0000-000000000002', 'acc02b16-0000-0000-0000-000000000001', 'text', '{"html":"<h3>Demonstrating mastery</h3><p>Top scores come from <strong>self-checking</strong>. Verify orientation with a check shot before observing. Confirm the angular misclosure meets the (n&minus;2)&times;180&deg; condition before computing bearings. Compute the linear misclosure as <em>hypot(&Sigma;Lat, &Sigma;Dep)</em> and report the precision ratio. Compute the area by the <strong>coordinate (shoelace) method</strong> and confirm it independently. Throughout, keep a clean, dated field book and show your reduction steps so a grader can follow your reasoning. A surveyor who checks their own work is the one this course is trying to produce.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0016-0000-0000-000000000003', 'acc02b16-0000-0000-0000-000000000001', 'callout', '{"type":"info","text":"Reduction order on the final: balance angles -> compute azimuths -> latitudes/departures -> misclosure and precision -> adjust (compass rule) -> coordinates -> area by coordinates."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee3010-0016-0000-0000-000000000004', 'acc02b16-0000-0000-0000-000000000001', 'key_takeaways', '{"title":"Key Takeaways","items":["The final integrates setup, observation, reduction, adjustment, and area.","Report misclosure, precision ratio, adjusted coordinates, and area.","Compute area by the coordinate (shoelace) method and check it independently.","Self-checking at every step is what the exam rewards."]}'::jsonb, 4);
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000001', 'Field book', 'The bound, permanent, ink record of original survey observations and sketches; kept as part of the legal survey record.', 'Right page = data, left page = sketch.', 'acc00002-0000-0000-0000-000000000002', 'acc02b01-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000002', 'Job-hazard scan', 'A quick pre-setup assessment of traffic, heat, overhead/buried utilities, and terrain hazards before occupying a point.', NULL, 'acc00002-0000-0000-0000-000000000002', 'acc02b01-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000003', 'Lining out an error', 'Correcting a field-book mistake by drawing one line through the wrong value, initialing it, and writing the correct value beside it (never erasing).', NULL, 'acc00002-0000-0000-0000-000000000002', 'acc02b01-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000004', 'Phase-comparison EDM', 'Distance measurement that compares the phase of an emitted modulated wave to its reflected return to resolve the fractional and whole wavelengths over the path.', 'Out-and-back path, divide by two.', 'acc00002-0000-0000-0000-000000000002', 'acc02b02-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000005', 'Prism (reflector) constant', 'A fixed offset, specific to the prism type, that must be entered so the EDM measures to the correct physical point.', 'Often 0 or -30 mm.', 'acc00002-0000-0000-0000-000000000002', 'acc02b02-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000006', 'Atmospheric (ppm) correction', 'An adjustment to EDM distance for the actual speed of light based on air temperature and pressure, applied in parts per million.', '~1 ppm per degree C.', 'acc00002-0000-0000-0000-000000000002', 'acc02b02-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000007', 'Total station', 'An instrument integrating an electronic theodolite, an EDM, and a processor that records HA/ZA/SD and computes coordinates.', 'Angles + distance + brains.', 'acc00002-0000-0000-0000-000000000002', 'acc02b03-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000008', 'Backsight orientation', 'Setting the horizontal circle to a known azimuth/bearing by sighting a known reference point so foresights are in the project frame.', NULL, 'acc00002-0000-0000-0000-000000000002', 'acc02b03-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000009', 'Optical/laser plummet check', 'A test that rotates the leveled instrument 180 deg to confirm the centering device still points at the marked station.', NULL, 'acc00002-0000-0000-0000-000000000002', 'acc02b03-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000010', 'Face left / face right (D/R)', 'The two telescope positions (vertical circle left, then plunged) used to observe an angle so instrumental errors cancel when meaned.', 'Direct and reverse.', 'acc00002-0000-0000-0000-000000000002', 'acc02b04-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000011', 'Collimation axis', 'The line of sight of the telescope; should be perpendicular to the trunnion axis.', NULL, 'acc00002-0000-0000-0000-000000000002', 'acc02b04-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000012', 'Trunnion (horizontal) axis', 'The axis about which the telescope tilts; should be perpendicular to the vertical standing axis.', NULL, 'acc00002-0000-0000-0000-000000000002', 'acc02b04-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000013', 'Method of repetition', 'Accumulating a horizontal angle n times on the circle and dividing by n to improve precision.', 'Resolution divided by n.', 'acc00002-0000-0000-0000-000000000002', 'acc02b05-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000014', 'Angular misclosure', 'The difference between the measured sum of interior angles and the geometric requirement (n-2) x 180 deg for a closed traverse.', NULL, 'acc00002-0000-0000-0000-000000000002', 'acc02b05-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000015', 'Angle-closure condition', 'For a closed polygon of n sides, the interior angles must sum to (n-2) x 180 degrees.', NULL, 'acc00002-0000-0000-0000-000000000002', 'acc02b05-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000016', 'Zenith angle', 'A vertical angle measured from the upward vertical: 0 deg straight up, 90 deg horizontal, 180 deg straight down.', 'Total stations usually report this.', 'acc00002-0000-0000-0000-000000000002', 'acc02b06-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000017', 'Vertical angle', 'Angle of the line of sight above (+) or below (-) the horizontal; equals 90 deg minus the zenith angle.', NULL, 'acc00002-0000-0000-0000-000000000002', 'acc02b06-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000018', 'Trigonometric leveling', 'Finding elevation difference from slope distance and zenith angle: delta-elev = S cos(z) + HI - HR.', 'Add instrument height, subtract rod height.', 'acc00002-0000-0000-0000-000000000002', 'acc02b06-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000019', 'Breaking chain', 'Measuring a slope in short horizontal segments, plumbing the downhill tape end, to obtain horizontal distance directly.', 'Step the tape down the hill.', 'acc00002-0000-0000-0000-000000000002', 'acc02b07-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000020', 'Sag correction', 'A negative tape correction for the curve of a suspended tape, proportional to weight squared and length cubed over tension squared.', NULL, 'acc00002-0000-0000-0000-000000000002', 'acc02b07-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000021', 'Slope reduction', 'Converting a slope distance to horizontal: H = L cos(slope angle), or H ≈ L - h²/(2L).', NULL, 'acc00002-0000-0000-0000-000000000002', 'acc02b07-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000022', 'Check shot', 'An independent observation to a third known point used to confirm the instrument''s orientation before collecting data.', 'Catches a bad backsight.', 'acc00002-0000-0000-0000-000000000002', 'acc02b08-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000023', 'Practical exam grading', 'Assessment of field procedure, accuracy, and documentation — not merely the final computed value.', NULL, 'acc00002-0000-0000-0000-000000000002', 'acc02b08-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000024', 'Open traverse', 'A traverse that runs from a known point to a point of unknown position, providing no mathematical closure check.', 'Common on route surveys.', 'acc00002-0000-0000-0000-000000000002', 'acc02b09-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000025', 'Deflection angle', 'The angle between a course and the prolongation of the preceding course, measured right (+) or left (-).', NULL, 'acc00002-0000-0000-0000-000000000002', 'acc02b09-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000026', 'Azimuth propagation', 'Computing each course''s azimuth from the previous course''s azimuth plus the measured angle, normalized to 0–360 deg.', NULL, 'acc00002-0000-0000-0000-000000000002', 'acc02b09-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000027', 'Linear misclosure', 'The hypotenuse of the summed latitude closure and summed departure closure of a traverse.', 'hypot(sum Lat, sum Dep).', 'acc00002-0000-0000-0000-000000000002', 'acc02b10-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000028', 'Precision ratio', 'Total traverse length divided by the linear misclosure, expressed as 1:N; larger N is better.', NULL, 'acc00002-0000-0000-0000-000000000002', 'acc02b10-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000029', 'Compass (Bowditch) rule', 'An adjustment that distributes traverse misclosure to each course in proportion to its length.', NULL, 'acc00002-0000-0000-0000-000000000002', 'acc02b10-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000030', 'Feature (descriptor) code', 'A short code attached to a survey point identifying the feature and controlling its CAD layer, symbol, and linework.', 'EP, FH, CL ...', 'acc00002-0000-0000-0000-000000000002', 'acc02b11-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000031', 'Field-to-finish', 'Coding points in the field so the office software draws the map (symbols and linework) automatically.', NULL, 'acc00002-0000-0000-0000-000000000002', 'acc02b11-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000032', 'Raw data file', 'The stored original observations (angles, distances, heights, setups) that can be re-reduced if a setup value was wrong.', NULL, 'acc00002-0000-0000-0000-000000000002', 'acc02b11-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000033', 'Height of instrument (HI)', 'In leveling, the elevation of the level''s line of sight = known elevation + backsight reading.', 'Add the backsight.', 'acc00002-0000-0000-0000-000000000002', 'acc02b12-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000034', 'Turning point (TP)', 'A temporary point on which both a foresight and the next backsight are taken to advance a level run.', NULL, 'acc00002-0000-0000-0000-000000000002', 'acc02b12-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000035', 'Balanced sights', 'Keeping backsight and foresight distances equal so collimation and curvature/refraction errors cancel.', NULL, 'acc00002-0000-0000-0000-000000000002', 'acc02b12-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000036', 'Monument', 'The physical marker (rod, pipe, capped rebar, concrete) that occupies a boundary corner.', 'Marks the corner; the corner is the legal point.', 'acc00002-0000-0000-0000-000000000002', 'acc02b13-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000037', 'Reference (witness) tie', 'A measured distance and bearing from a corner to a nearby permanent object, recorded so the corner can be re-established.', NULL, 'acc00002-0000-0000-0000-000000000002', 'acc02b13-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000038', 'Original monument', 'A monument set by the creating surveyor; when undisturbed it controls over record distances and bearings.', 'Highest dignity of evidence.', 'acc00002-0000-0000-0000-000000000002', 'acc02b13-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000039', 'Profile leveling', 'Leveling along a centerline at regular stations to record the longitudinal ground profile.', 'Side view along the line.', 'acc00002-0000-0000-0000-000000000002', 'acc02b14-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000040', 'Intermediate foresight (IFS)', 'A ground-rod reading taken from the current HI that records elevation but does not move the instrument.', NULL, 'acc00002-0000-0000-0000-000000000002', 'acc02b14-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000041', 'Cross-section', 'Ground elevations measured at offsets perpendicular to the centerline at a station, used for earthwork.', NULL, 'acc00002-0000-0000-0000-000000000002', 'acc02b14-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000042', 'Radial (side-shot) topo', 'Collecting detail points by shooting them directly from an oriented control setup, each tagged with a feature code.', NULL, 'acc00002-0000-0000-0000-000000000002', 'acc02b15-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000043', 'Control-first workflow', 'Establishing and adjusting the control traverse before any detail collection, because detail inherits control error.', NULL, 'acc00002-0000-0000-0000-000000000002', 'acc02b15-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000044', 'QA/QC of a survey deliverable', 'Checking closure, spot-checking coordinates, verifying linework, and confirming area by an independent method before signing.', NULL, 'acc00002-0000-0000-0000-000000000002', 'acc02b15-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000045', 'Coordinate (shoelace) area', 'Area of a polygon computed from station coordinates: half the absolute value of the sum of (x_i*y_{i+1} - x_{i+1}*y_i).', NULL, 'acc00002-0000-0000-0000-000000000002', 'acc02b16-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000046', 'Reduction order', 'Balance angles, compute azimuths, latitudes/departures, misclosure, adjust, coordinates, then area.', NULL, 'acc00002-0000-0000-0000-000000000002', 'acc02b16-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee3040-0000-0000-0000-000000000047', 'Self-checking', 'Building independent verification (check shots, closure checks, area cross-checks) into a survey to catch blunders before signing.', NULL, 'acc00002-0000-0000-0000-000000000002', 'acc02b16-0000-0000-0000-000000000001', 'surveying', ARRAY['buildout','module-30']::text[], true, 'approved', 'intermediate');
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3030-0000-0000-0000-000000000001', 'How should a wrong value be corrected in a survey field book?', 'multiple_choice', '["Erase it and write the correct value","Draw one line through it, initial it, and write the correct value beside it","Scribble it out completely so it can''t be read","Tear out the page and start over"]'::jsonb, 'Draw one line through it, initial it, and write the correct value beside it', 'Field notes are a permanent legal record. Errors are lined out (single line), initialed, and corrected beside, never erased, so the original remains legible.', 'easy', 'acc00002-0000-0000-0000-000000000002', 'acc02b01-0000-0000-0000-000000000001', ARRAY['buildout','module-30']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3030-0000-0000-0000-000000000002', 'Original field notes in Texas are considered part of the legal survey record and must be retained.', 'true_false', '["True","False"]'::jsonb, 'True', 'Texas Board rules (22 TAC Ch. 663) require surveyors to maintain the records supporting a survey, including original field notes.', 'easy', 'acc00002-0000-0000-0000-000000000002', 'acc02b01-0000-0000-0000-000000000001', ARRAY['buildout','module-30']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3030-0000-0000-0000-000000000003', 'An EDM reports a slope distance of 250.00 ft. If the entered prism constant is wrong by +0.03 ft, what is the effect on the measured distance?', 'multiple_choice', '["The distance is biased by 0.03 ft regardless of length","The error scales with distance (ppm)","There is no effect because the EDM self-corrects","Only the vertical component is affected"]'::jsonb, 'The distance is biased by 0.03 ft regardless of length', 'The prism constant is a fixed additive offset; a wrong constant biases every measured distance by that constant, independent of length (unlike ppm errors, which scale).', 'medium', 'acc00002-0000-0000-0000-000000000002', 'acc02b02-0000-0000-0000-000000000001', ARRAY['buildout','module-30']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3030-0000-0000-0000-000000000004', 'The atmospheric (ppm) correction for an EDM accounts for which of the following?', 'multiple_choice', '["The offset of the prism''s optical center","The actual speed of light, which varies with air temperature and pressure","Earth curvature over the line","The instrument''s leveling error"]'::jsonb, 'The actual speed of light, which varies with air temperature and pressure', 'The speed of light through air depends on temperature and pressure; the ppm correction adjusts the distance for the real propagation speed.', 'medium', 'acc00002-0000-0000-0000-000000000002', 'acc02b02-0000-0000-0000-000000000001', ARRAY['buildout','module-30']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3030-0000-0000-0000-000000000005', 'What is the purpose of taking a check shot to a third known point after orienting a total station?', 'multiple_choice', '["To recharge the battery","To confirm the orientation (backsight) is correct before collecting data","To set the prism constant","To level the instrument"]'::jsonb, 'To confirm the orientation (backsight) is correct before collecting data', 'A check shot to an independent known point verifies that the occupied point, instrument height, and backsight azimuth were entered correctly before production work begins.', 'easy', 'acc00002-0000-0000-0000-000000000002', 'acc02b03-0000-0000-0000-000000000001', ARRAY['buildout','module-30']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3030-0000-0000-0000-000000000006', 'When you rotate a leveled total station 180 degrees and the optical/laser plummet drifts off the marked point, what does this indicate?', 'multiple_choice', '["The battery is low","The plummet is out of adjustment","The prism constant is wrong","The instrument is perfectly adjusted"]'::jsonb, 'The plummet is out of adjustment', 'A correctly adjusted plummet stays on the point through a 180-degree rotation. Drift means it is out of adjustment, so you have been centering over a circle rather than the point.', 'medium', 'acc00002-0000-0000-0000-000000000002', 'acc02b03-0000-0000-0000-000000000001', ARRAY['buildout','module-30']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3030-0000-0000-0000-000000000007', 'Measuring an angle in both face-left and face-right and meaning the results cancels which error?', 'multiple_choice', '["Standing-axis (plate not level) error","Collimation error","Centering (setup) error","Reading-resolution error"]'::jsonb, 'Collimation error', 'Collimation, horizontal-axis, and vertical-index errors reverse sign between faces and cancel when meaned. Standing-axis error does not reverse, so it is not cancelled by face reversal.', 'medium', 'acc00002-0000-0000-0000-000000000002', 'acc02b04-0000-0000-0000-000000000001', ARRAY['buildout','module-30']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3030-0000-0000-0000-000000000008', 'In a properly adjusted theodolite, the line of sight (collimation axis) should be perpendicular to the trunnion (horizontal) axis.', 'true_false', '["True","False"]'::jsonb, 'True', 'The three axes must be mutually perpendicular: the line of sight perpendicular to the trunnion axis, which is perpendicular to the vertical standing axis.', 'easy', 'acc00002-0000-0000-0000-000000000002', 'acc02b04-0000-0000-0000-000000000001', ARRAY['buildout','module-30']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3030-0000-0000-0000-000000000009', 'The interior angles of a closed six-sided traverse should theoretically sum to how many degrees?', 'numeric_input', '[]'::jsonb, '720', '(n - 2) x 180 = (6 - 2) x 180 = 4 x 180 = 720 degrees.', 'easy', 'acc00002-0000-0000-0000-000000000002', 'acc02b05-0000-0000-0000-000000000001', ARRAY['buildout','module-30']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3030-0000-0000-0000-000000000010', 'The method of repetition improves a measured horizontal angle primarily by:', 'multiple_choice', '["Eliminating the prism constant","Effectively dividing the reading resolution by the number of repetitions and averaging pointing error","Correcting for atmospheric refraction","Removing the need to level the instrument"]'::jsonb, 'Effectively dividing the reading resolution by the number of repetitions and averaging pointing error', 'Accumulating the angle n times and dividing by n divides the circle''s reading resolution by n and averages random pointing error.', 'medium', 'acc00002-0000-0000-0000-000000000002', 'acc02b05-0000-0000-0000-000000000001', ARRAY['buildout','module-30']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3030-0000-0000-0000-000000000011', 'A total station reads a zenith angle of 90 degrees. The line of sight is:', 'multiple_choice', '["Pointing straight up","Horizontal","Pointing straight down","Inclined 45 degrees"]'::jsonb, 'Horizontal', 'Zenith angle is measured from the upward vertical: 0 deg is straight up, 90 deg is horizontal, and 180 deg is straight down.', 'easy', 'acc00002-0000-0000-0000-000000000002', 'acc02b06-0000-0000-0000-000000000001', ARRAY['buildout','module-30']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3030-0000-0000-0000-000000000012', 'A slope distance of 300.00 ft is measured at a zenith angle of 85 degrees. What is the horizontal distance (ft)?', 'numeric_input', '[]'::jsonb, '298.86', 'H = S sin(z) = 300.00 x sin(85 deg) = 300.00 x 0.99619 = 298.86 ft.', 'medium', 'acc00002-0000-0000-0000-000000000002', 'acc02b06-0000-0000-0000-000000000001', ARRAY['buildout','module-30']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3030-0000-0000-0000-000000000013', 'A line is measured along a slope as 152.00 ft at a slope angle of 6 degrees. What is the horizontal distance (ft)?', 'numeric_input', '[]'::jsonb, '151.17', 'H = L cos(alpha) = 152.00 x cos(6 deg) = 152.00 x 0.99452 = 151.17 ft.', 'medium', 'acc00002-0000-0000-0000-000000000002', 'acc02b07-0000-0000-0000-000000000001', ARRAY['buildout','module-30']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3030-0000-0000-0000-000000000014', 'If a steel tape is used at a temperature hotter than its standardization temperature, the tape is longer than nominal and therefore:', 'multiple_choice', '["Reads the distance too long; correction is negative","Reads the distance too short; correction is positive","Is unaffected by temperature","Must be re-standardized at every reading"]'::jsonb, 'Reads the distance too short; correction is positive', 'A tape longer than nominal lays down fewer tape-lengths, so it reports a distance that is too short; the temperature correction is positive (added).', 'hard', 'acc00002-0000-0000-0000-000000000002', 'acc02b07-0000-0000-0000-000000000001', ARRAY['buildout','module-30']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3030-0000-0000-0000-000000000015', 'On the midterm practical, a poorly leveled or off-center instrument is problematic because:', 'multiple_choice', '["It drains the battery faster","It biases every observation taken from that setup","It only affects vertical angles","It has no effect if you measure quickly"]'::jsonb, 'It biases every observation taken from that setup', 'Centering and leveling errors propagate into every angle and distance from that setup, making setup quality the most common cause of a failed practical.', 'easy', 'acc00002-0000-0000-0000-000000000002', 'acc02b08-0000-0000-0000-000000000001', ARRAY['buildout','module-30']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3030-0000-0000-0000-000000000016', 'Which statement about an open traverse is correct?', 'multiple_choice', '["It returns to its starting point","It provides a mathematical closure check","It ends at a point of unknown position and cannot self-check","It is required for boundary surveys"]'::jsonb, 'It ends at a point of unknown position and cannot self-check', 'An open traverse runs from a known point to an unknown point, so there is no geometric condition to check the work — redundancy must be added manually.', 'easy', 'acc00002-0000-0000-0000-000000000002', 'acc02b09-0000-0000-0000-000000000001', ARRAY['buildout','module-30']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3030-0000-0000-0000-000000000017', 'A closed-loop traverse has a latitude closure of +0.18 ft and a departure closure of -0.24 ft. What is the linear misclosure (ft)?', 'numeric_input', '[]'::jsonb, '0.30', 'Linear misclosure = hypot(0.18, 0.24) = sqrt(0.18^2 + 0.24^2) = sqrt(0.0324 + 0.0576) = sqrt(0.09) = 0.30 ft.', 'medium', 'acc00002-0000-0000-0000-000000000002', 'acc02b10-0000-0000-0000-000000000001', ARRAY['buildout','module-30']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3030-0000-0000-0000-000000000018', 'A traverse with total length 2400 ft has a linear misclosure of 0.20 ft. The precision ratio is closest to:', 'multiple_choice', '["1:120","1:1200","1:12000","1:480"]'::jsonb, '1:12000', 'Precision = total length / misclosure = 2400 / 0.20 = 12000, written 1:12000.', 'medium', 'acc00002-0000-0000-0000-000000000002', 'acc02b10-0000-0000-0000-000000000001', ARRAY['buildout','module-30']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3030-0000-0000-0000-000000000019', 'The compass (Bowditch) rule distributes traverse misclosure to each course in proportion to its length.', 'true_false', '["True","False"]'::jsonb, 'True', 'The compass rule corrects each course''s latitude and departure in proportion to the course length over the total traverse length.', 'easy', 'acc00002-0000-0000-0000-000000000002', 'acc02b10-0000-0000-0000-000000000001', ARRAY['buildout','module-30']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3030-0000-0000-0000-000000000020', 'Why should the raw data file from a data collector never be deleted?', 'multiple_choice', '["It is required for the battery to charge","It alone allows the entire dataset to be re-reduced if a setup value (HI, prism constant, backsight) was wrong","It contains the firmware","It stores the office CAD drawing"]'::jsonb, 'It alone allows the entire dataset to be re-reduced if a setup value (HI, prism constant, backsight) was wrong', 'The raw file holds the original observations and setup values, so it is the only way to correctly re-reduce data after a setup-entry error.', 'medium', 'acc00002-0000-0000-0000-000000000002', 'acc02b11-0000-0000-0000-000000000001', ARRAY['buildout','module-30']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3030-0000-0000-0000-000000000021', 'Feature (descriptor) codes recorded in the field are used to:', 'multiple_choice', '["Calibrate the EDM","Drive automatic field-to-finish linework, layers, and symbols in CAD","Level the instrument","Compute the prism constant"]'::jsonb, 'Drive automatic field-to-finish linework, layers, and symbols in CAD', 'A controlled code list maps each descriptor to a layer, symbol, and linework behavior so the office software draws the map automatically.', 'easy', 'acc00002-0000-0000-0000-000000000002', 'acc02b11-0000-0000-0000-000000000001', ARRAY['buildout','module-30']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3030-0000-0000-0000-000000000022', 'A benchmark has elevation 100.00 ft. A backsight of 4.32 ft is read, then a foresight of 6.18 ft to a new point. What is the elevation of the new point (ft)?', 'numeric_input', '[]'::jsonb, '98.14', 'HI = 100.00 + 4.32 = 104.32; new elevation = HI - FS = 104.32 - 6.18 = 98.14 ft.', 'medium', 'acc00002-0000-0000-0000-000000000002', 'acc02b12-0000-0000-0000-000000000001', ARRAY['buildout','module-30']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3030-0000-0000-0000-000000000023', 'Keeping backsight and foresight distances balanced (equal) at each level setup primarily cancels:', 'multiple_choice', '["Rod graduation error","Collimation error and curvature/refraction","The prism constant","Angular misclosure"]'::jsonb, 'Collimation error and curvature/refraction', 'Equal sight lengths make the line-of-sight collimation error and the curvature/refraction effect equal on backsight and foresight, so they cancel in the elevation difference.', 'medium', 'acc00002-0000-0000-0000-000000000002', 'acc02b12-0000-0000-0000-000000000001', ARRAY['buildout','module-30']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3030-0000-0000-0000-000000000024', 'Under Texas Board rules, a monument set to mark a property corner must be:', 'multiple_choice', '["Left uncapped to avoid liability","Capped/identified with the responsible RPLS''s registration or firm number","Made only of wood","Set by any crew member without supervision"]'::jsonb, 'Capped/identified with the responsible RPLS''s registration or firm number', '22 TAC Ch. 663 requires set property-corner monuments to be identified with the responsible RPLS or firm number; setting boundary monuments is professional practice done under RPLS responsibility.', 'medium', 'acc00002-0000-0000-0000-000000000002', 'acc02b13-0000-0000-0000-000000000001', ARRAY['buildout','module-30']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3030-0000-0000-0000-000000000025', 'When an undisturbed original monument is recovered, boundary law says it controls over the record distances and bearings.', 'true_false', '["True","False"]'::jsonb, 'True', 'An undisturbed original monument is the highest dignity of evidence and controls over measured distances and bearings in retracement.', 'medium', 'acc00002-0000-0000-0000-000000000002', 'acc02b13-0000-0000-0000-000000000001', ARRAY['buildout','module-30']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3030-0000-0000-0000-000000000026', 'At station 2+50 the ground elevation is 99.2 ft and the design grade is 100.0 ft. This represents:', 'multiple_choice', '["0.8 ft of cut","0.8 ft of fill","No cut or fill","1.8 ft of fill"]'::jsonb, '0.8 ft of fill', 'Ground (99.2) is below grade (100.0) by 0.8 ft, so material must be added: 0.8 ft of fill.', 'medium', 'acc00002-0000-0000-0000-000000000002', 'acc02b14-0000-0000-0000-000000000001', ARRAY['buildout','module-30']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3030-0000-0000-0000-000000000027', 'In profile leveling, an intermediate foresight (IFS) read on the ground:', 'multiple_choice', '["Advances the instrument to a new HI","Records a ground elevation (HI - IFS) but does not carry elevation forward","Is the same as a benchmark","Must equal the backsight"]'::jsonb, 'Records a ground elevation (HI - IFS) but does not carry elevation forward', 'Intermediate foresights record ground elevations from the current HI; only turning points carry the elevation forward when the instrument moves.', 'medium', 'acc00002-0000-0000-0000-000000000002', 'acc02b14-0000-0000-0000-000000000001', ARRAY['buildout','module-30']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3030-0000-0000-0000-000000000028', 'Why must control be established and adjusted before collecting topographic detail?', 'multiple_choice', '["To charge the data collector","Because detail shots inherit the error of the control setups they are taken from","Because topo cannot be coded otherwise","It is not necessary; order does not matter"]'::jsonb, 'Because detail shots inherit the error of the control setups they are taken from', 'Radial detail shots are referenced to control; if control is out of spec, every detail point is wrong and must be re-collected.', 'easy', 'acc00002-0000-0000-0000-000000000002', 'acc02b15-0000-0000-0000-000000000001', ARRAY['buildout','module-30']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3030-0000-0000-0000-000000000029', 'Using the coordinate (shoelace) method, a triangle has vertices A(0,0), B(100,0), C(100,80). What is its area (sq ft)?', 'numeric_input', '[]'::jsonb, '4000', 'Area = 0.5 |x_A(y_B - y_C) + x_B(y_C - y_A) + x_C(y_A - y_B)| = 0.5 |0(0-80) + 100(80-0) + 100(0-0)| = 0.5 x 8000 = 4000 sq ft.', 'medium', 'acc00002-0000-0000-0000-000000000002', 'acc02b16-0000-0000-0000-000000000001', ARRAY['buildout','module-30']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee3030-0000-0000-0000-000000000030', 'What is the correct order of traverse reduction on the final exam?', 'multiple_choice', '["Area, coordinates, misclosure, balance angles","Balance angles, compute azimuths, latitudes/departures, misclosure, adjust, coordinates, area","Coordinates first, then balance angles, then azimuths","Compute area before checking angular misclosure"]'::jsonb, 'Balance angles, compute azimuths, latitudes/departures, misclosure, adjust, coordinates, area', 'Angles are balanced first so bearings/azimuths are correct, then latitudes/departures and misclosure, adjustment, coordinates, and finally area by coordinates.', 'medium', 'acc00002-0000-0000-0000-000000000002', 'acc02b16-0000-0000-0000-000000000001', ARRAY['buildout','module-30']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
