INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee3060-0000-0000-0000-000000000001', 'A traverse course has a length of {{dist:f2}} ft and a bearing of N {{ang:f0}} deg E. Compute the DEPARTURE (east-west component) of this course in feet.', 'numeric_input', '[]'::jsonb, '0', 'Departure = d sin(bearing) = {{dist:f2}} x sin({{ang:f0}} deg) = {{_answer}} ft east. (Its latitude, d cos(bearing), would be {{lat:f2}} ft north.)', 'medium', 'acc00002-0000-0000-0000-000000000002', NULL, ARRAY['buildout','module-30','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee3050-0000-0000-0000-000000000001', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee3060-0000-0000-0000-000000000002', 'A closed-loop traverse has a closure in latitude of {{clat:f2}} ft and a closure in departure of {{cdep:f2}} ft. Compute the LINEAR MISCLOSURE (ft).', 'numeric_input', '[]'::jsonb, '0', 'The linear misclosure is the hypotenuse of the latitude and departure closures: hypot({{clat:f2}}, {{cdep:f2}}) = {{_answer}} ft.', 'medium', 'acc00002-0000-0000-0000-000000000002', NULL, ARRAY['buildout','module-30','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee3050-0000-0000-0000-000000000002', 0.01);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee3060-0000-0000-0000-000000000003', 'A triangular parcel has corner coordinates A(0, 0), B({{bx:f1}}, 0), and C({{bx:f1}}, {{cy:f1}}) in feet. Compute the AREA by coordinates (square feet).', 'numeric_input', '[]'::jsonb, '0', 'With A at the origin, the coordinate (shoelace) area reduces to 0.5 x base x height = 0.5 x {{bx:f1}} x {{cy:f1}} = {{_answer}} sq ft.', 'medium', 'acc00002-0000-0000-0000-000000000002', NULL, ARRAY['buildout','module-30','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee3050-0000-0000-0000-000000000003', 0.5);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee3060-0000-0000-0000-000000000004', 'A benchmark has elevation {{bm:f2}} ft. A backsight of {{bs:f2}} ft is read on the benchmark, then a foresight of {{fs:f2}} ft is read on a new point. Compute the elevation of the new point (ft).', 'numeric_input', '[]'::jsonb, '0', 'HI = {{bm:f2}} + {{bs:f2}} = {{hi:f2}} ft; new elevation = HI - FS = {{hi:f2}} - {{fs:f2}} = {{_answer}} ft.', 'easy', 'acc00002-0000-0000-0000-000000000002', NULL, ARRAY['buildout','module-30','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee3050-0000-0000-0000-000000000004', 0.005);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee3060-0000-0000-0000-000000000005', 'A total station measures a slope distance of {{sd:f2}} ft at a zenith angle of {{z:f0}} deg. Compute the HORIZONTAL distance (ft).', 'numeric_input', '[]'::jsonb, '0', 'Using the zenith angle, H = S sin(z) = {{sd:f2}} x sin({{z:f0}} deg) = {{_answer}} ft. The vertical component V = S cos(z) = {{vert:f2}} ft.', 'medium', 'acc00002-0000-0000-0000-000000000002', NULL, ARRAY['buildout','module-30','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee3050-0000-0000-0000-000000000005', 0.02);
