-- 361_buildout_m30.sql (GENERATED) — fill empty lessons for "ACC SRVY 1335 — Land Surveying Applications (Lab)"
-- Module acc00002-0000-0000-0000-000000000002. Namespaced by tag 'buildout' / created_by 'buildout:m30' so pre-existing rows are untouched.
BEGIN;
DELETE FROM question_bank     WHERE module_id='acc00002-0000-0000-0000-000000000002' AND 'buildout' = ANY(tags);
DELETE FROM flashcards        WHERE module_id='acc00002-0000-0000-0000-000000000002' AND 'buildout' = ANY(tags);
DELETE FROM problem_templates WHERE module_id='acc00002-0000-0000-0000-000000000002' AND created_by='buildout:m30';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['Survey field work is hazardous: traffic, heat, terrain, and overhead/buried utilities are the leading risks; high-visibility vests and a traffic plan are mandatory near roadways.','Every check-out of an instrument begins with an inventory and a quick physical/optical inspection before leaving the lab.','A field book is a permanent legal record: ink, dated, named, gridded notes on the right page and sketches on the left, with no erasures (line out, initial, re-enter).','Texas Board of Professional Land Surveying rules require that original field notes be retained as part of the survey record.']::text[], learning_objectives=ARRAY['Apply field and lab safety practices for surveying near traffic, on construction sites, and in heat.','Identify the major instruments and accessories in a survey kit and verify a check-out inventory.','Set up a survey field book that meets professional documentation standards.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc02b01-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc02b01-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Phase-comparison EDM measures the fraction of a wavelength returned and counts whole wavelengths to resolve distance; pulse/time-of-flight EDM times the round trip.','Every EDM/prism pairing has a reflector (prism) constant that must be entered or the distance is biased by that constant.','Atmospheric conditions change the speed of light, so a ppm correction from temperature and pressure must be applied for precise work.','EDM measures SLOPE distance along the line of sight; horizontal distance = slope distance times sin(zenith) or cos(vertical angle).']::text[], learning_objectives=ARRAY['Explain how phase-comparison EDM determines distance from a modulated carrier.','Account for prism (reflector) constant, atmospheric correction (ppm), and instrument constants.','Reduce a measured slope distance to a horizontal distance using the vertical/zenith angle.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc02b02-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc02b02-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Centering and leveling are iterative: rough center with tripod legs, level with foot screws, fine-center with the tribrach shift, relevel, repeat until both hold.','A total station integrates an electronic theodolite (angles) with an EDM (distance) and an onboard processor that reduces shots to coordinates.','Orientation requires occupying a known point and backsighting another known point/azimuth so all subsequent shots are in the project coordinate frame.','Routinely test pointing/collimation and the plummet; an out-of-adjustment plummet centers you over the wrong point.']::text[], learning_objectives=ARRAY['Set up and precisely level a total station over a point using the optical/laser plummet.','Perform a two-peg / collimation check and orient the instrument by backsight.','Record a measured point set (HA, ZA, SD) and verify it reduces to sensible coordinates.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc02b03-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc02b03-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['A theodolite measures horizontal and vertical angles precisely; its vertical, horizontal (trunnion), and sight (collimation) axes should be mutually perpendicular.','Measuring an angle in both faces (direct and reverse) and meaning the two cancels collimation, horizontal-axis, and vertical-index errors.','Centering errors and circle eccentricity are reduced by precise setup and by reading both faces.','The mean of face-left and face-right is the best single estimate; a large D/R spread signals a blunder or maladjustment.']::text[], learning_objectives=ARRAY['Identify the parts of an optical/digital theodolite and the axes that must be mutually perpendicular.','Measure a horizontal angle in direct and reverse (face left / face right) to cancel instrumental errors.','Mean a set of direct/reverse pointings and judge whether the spread is acceptable.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc02b04-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc02b04-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['The method of repetition accumulates an angle several times so the reading resolution is effectively divided by the number of repetitions.','Direction (set) methods point to several targets from one zero, then mean each set; both reduce random pointing error.','Interior angles of a closed n-sided polygon must sum to (n-2) x 180 degrees; the difference is the angular misclosure.','Acceptable angular misclosure is often specified as a constant times the square root of the number of angles.']::text[], learning_objectives=ARRAY['Measure a horizontal angle by repetition (multiple turnings) and by direction sets.','Compute the mean angle, the angular spread, and the standard deviation of a set.','Apply the angle-closure condition for a closed polygon to detect angular misclosure.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc02b05-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc02b05-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Zenith angle is measured from straight up: 0 deg = up, 90 deg = horizontal, 180 deg = straight down; vertical angle = 90 deg - zenith.','Horizontal distance = slope distance x sin(zenith); vertical distance = slope distance x cos(zenith).','Trigonometric leveling computes elevation difference as V + HI - HR (instrument height minus rod/target height).','Observing the zenith angle in both faces removes vertical-circle index error.']::text[], learning_objectives=ARRAY['Distinguish vertical angles (from horizontal) from zenith angles (from the upward vertical).','Reduce a slope distance to horizontal and vertical components using the zenith angle.','Compute trigonometric elevation difference including instrument and target heights.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc02b06-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc02b06-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Standard taping requires correct horizontal alignment, full plumbing of the tape ends, and a standard pull (tension), with the tape supported or sag-corrected.','Systematic tape corrections include temperature, pull, sag, and slope; each has a known sign and formula.','A slope distance is reduced to horizontal by H = L cos(slope angle) or by the slope-correction approximation.','EDM and a carefully taped distance should agree to within a few hundredths over a short course; a larger difference signals a blunder.']::text[], learning_objectives=ARRAY['Execute proper taping: alignment, plumbing, tension, and breaking chain on slopes.','Apply taping corrections for temperature, tension/pull, sag, and slope.','Compare a taped distance to an EDM distance and judge whether they agree within tolerance.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc02b07-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc02b07-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['The midterm practical tests setup speed and accuracy: center and level within tolerance, orient correctly, and take a verified check shot.','You will be graded on procedure and documentation, not just the final number.','Reduce field observations (HA mean, slope-to-horizontal, trig elevation) without notes, showing your work.','Calm, methodical procedure beats rushing — most exam errors are blunders from skipped steps.']::text[], learning_objectives=ARRAY['Demonstrate a timed, graded total-station setup, orientation, and check shot.','Measure and reduce a horizontal angle (D/R) and a distance under exam conditions.','Document the practical exam in a clean, defensible field book.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc02b08-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc02b08-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['An open traverse starts at a known point and ends at an unknown point, so there is no built-in mathematical check on the work.','Successive azimuths are propagated by adding the measured deflection or interior angle to the previous azimuth (then normalizing into 0–360 deg).','Because open traverses cannot self-check, redundant measurements (double angles, tie shots, repeated distances) are essential.','Open traverses suit route surveys (pipelines, roads) where returning to the start is impractical.']::text[], learning_objectives=ARRAY['Run an open traverse: occupy, backsight, foresight, and step station to station.','Convert measured angles and a starting azimuth into successive course azimuths.','Recognize that an open traverse has no closure check and plan independent verification.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc02b09-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc02b09-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['A closed traverse returns to its start (loop) or ties two known points (link), giving a mathematical check on the field work.','Linear misclosure = hypot(sum of latitudes, sum of departures); for a loop both sums should ideally be zero.','Precision ratio = linear misclosure divided by total traverse length, expressed as 1:N.','The compass (Bowditch) rule distributes the misclosure to each course in proportion to its length.']::text[], learning_objectives=ARRAY['Run a closed-loop traverse and compute angular and linear misclosure.','Compute latitudes and departures and the linear misclosure by hypotenuse of the closures.','Express closure as a precision ratio and adjust the traverse by the compass (Bowditch) rule.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc02b10-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc02b10-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['A data collector stores raw observations and reduced coordinates electronically, eliminating transcription error from hand notes.','Feature (descriptor) codes tell the office software what each point is and how to connect points into linework.','Consistent point numbering and a controlled code list make field-to-finish drafting automatic and repeatable.','Always keep the raw data file; back up to a second medium before leaving the field.']::text[], learning_objectives=ARRAY['Operate a data collector to record points with feature codes and attributes.','Apply consistent point numbering and field-to-finish coding for automated drafting.','Manage and back up survey data files (raw, coordinate, and code list).']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc02b11-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc02b11-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['Differential leveling transfers elevation from a benchmark through turning points using a level and rod.','HI method: HI = known elevation + backsight; new elevation = HI - foresight.','Closing a loop back to the benchmark gives a misclosure that checks the work.','Balancing backsight and foresight distances cancels collimation and curvature/refraction errors.']::text[], learning_objectives=ARRAY['Run a differential level loop using backsights, foresights, turning points, and benchmarks.','Reduce notes by the height-of-instrument (HI) method to compute elevations.','Compute and check level-loop misclosure and balance backsight/foresight distances.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc02b12-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc02b12-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['A monument is the physical marker of a corner; durability and a permanent record are what give it long-term legal value.','Texas requires a Registered Professional Land Surveyor (RPLS) to cap set monuments with the firm/RPLS number under Board rules.','Reference (witness) ties and a detailed field record let a future surveyor recover the corner even if the monument is disturbed.','Recovering an original monument controls over setting a new one; original monuments hold the highest dignity in boundary law.']::text[], learning_objectives=ARRAY['Set a durable boundary monument and reference it with witness/reference ties.','Cap monuments per Texas requirements and record the corner properly.','Distinguish setting a new corner from recovering and perpetuating an original monument.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc02b13-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc02b13-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Profile leveling records ground elevation along a line at regular stations to produce a longitudinal profile.','Intermediate foresights (rod shots) on the ground are read from the same HI; only turning points carry elevation forward.','Cross-sections capture ground elevation at offsets left and right of the centerline at each station.','Comparing ground elevation to a design grade yields cut (ground above grade) or fill (ground below grade).']::text[], learning_objectives=ARRAY['Run profile leveling along a centerline using stationing and intermediate foresights.','Take cross-sections perpendicular to the centerline and record offset/elevation pairs.','Plot a ground profile and cross-sections and compute simple cut/fill at grade.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc02b14-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc02b14-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=45, key_takeaways=ARRAY['The capstone integrates every lab skill: control, angles, distances, leveling, topo collection, reduction, adjustment, area, and drafting.','Begin with control: run and adjust a closed traverse meeting the precision spec before collecting detail.','Collect topographic detail by radial shots with feature codes for automated field-to-finish drafting.','QA/QC every deliverable: check closure, spot-check coordinates, verify linework, and confirm area by an independent method.']::text[], learning_objectives=ARRAY['Plan and execute a closed control traverse with topographic detail collection.','Reduce, adjust, and compute area for the traverse and verify closure to specification.','Produce a finished, QA/QC-checked drawing deliverable from field-to-finish data.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc02b15-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc02b15-0000-0000-0000-000000000001';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=45, key_takeaways=ARRAY['The final practical is a comprehensive, independent assessment of semester field and reduction skills.','You set up, orient, observe a small traverse, and reduce it to coordinates and closure on your own.','Computing area by coordinates and reporting a precision ratio demonstrates mastery.','Self-checking — a backsight check shot, a closure check, an independent area check — is the mark of a competent surveyor.']::text[], learning_objectives=ARRAY['Independently execute a complete short survey task under timed exam conditions.','Reduce field data to coordinates, compute traverse closure, and compute area.','Demonstrate professional documentation and self-checking throughout.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='acc02b16-0000-0000-0000-000000000001';
DELETE FROM lesson_blocks WHERE lesson_id='acc02b16-0000-0000-0000-000000000001';
  'eeee3050-0000-0000-0000-000000000001', 'Latitude and departure of a traverse course', 'Latitude and departure of a traverse course', 'Surveying Applications (Lab) — Traverse', 'Latitude and departure', 'numeric_input', 'medium', 'A traverse course has a length of {{dist:f2}} ft and a bearing of N {{ang:f0}} deg E. Compute the DEPARTURE (east-west component) of this course in feet.', 'dist*sin(toRad(ang))', '{"decimals":2,"unit":"ft","tolerance":0.05}', '[{"name":"ang","type":"integer","min":12,"max":78},{"name":"dist","type":"float","min":150,"max":700,"decimals":2}]'::jsonb, '[{"name":"lat","formula":"dist*cos(toRad(ang))"}]'::jsonb, '[{"step_number":1,"title":"Departure formula","formula":"Dep = d sin(bearing)","calculation_template":"{{dist:f2}} x sin({{ang:f0}} deg)"},{"step_number":2,"title":"Compute","result_template":"Departure = {{_answer}} ft (east, positive)"}]'::jsonb, '{"method":"none"}'::jsonb, 'Departure = d sin(bearing) = {{dist:f2}} x sin({{ang:f0}} deg) = {{_answer}} ft east. (Its latitude, d cos(bearing), would be {{lat:f2}} ft north.)', 'acc00002-0000-0000-0000-000000000002', ARRAY['buildout','module-30','practice']::text[], true, 'buildout:m30');
  'eeee3050-0000-0000-0000-000000000002', 'Linear misclosure of a closed traverse', 'Linear misclosure of a closed traverse', 'Surveying Applications (Lab) — Traverse', 'Misclosure', 'numeric_input', 'medium', 'A closed-loop traverse has a closure in latitude of {{clat:f2}} ft and a closure in departure of {{cdep:f2}} ft. Compute the LINEAR MISCLOSURE (ft).', 'hypot(clat,cdep)', '{"decimals":2,"unit":"ft","tolerance":0.01}', '[{"name":"clat","type":"float","min":-0.5,"max":0.5,"decimals":2},{"name":"cdep","type":"float","min":-0.5,"max":0.5,"decimals":2}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Misclosure","formula":"e = hypot(sum Lat, sum Dep)","calculation_template":"hypot({{clat:f2}}, {{cdep:f2}})"},{"step_number":2,"title":"Result","result_template":"Linear misclosure = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'The linear misclosure is the hypotenuse of the latitude and departure closures: hypot({{clat:f2}}, {{cdep:f2}}) = {{_answer}} ft.', 'acc00002-0000-0000-0000-000000000002', ARRAY['buildout','module-30','practice']::text[], true, 'buildout:m30');
  'eeee3050-0000-0000-0000-000000000003', 'Area of a triangular parcel by coordinates', 'Area of a triangular parcel by coordinates', 'Surveying Applications (Lab) — Area', 'Coordinate area', 'numeric_input', 'medium', 'A triangular parcel has corner coordinates A(0, 0), B({{bx:f1}}, 0), and C({{bx:f1}}, {{cy:f1}}) in feet. Compute the AREA by coordinates (square feet).', '0.5*abs(bx*cy)', '{"decimals":1,"unit":"sq ft","tolerance":0.5}', '[{"name":"bx","type":"float","min":80,"max":300,"decimals":1},{"name":"cy","type":"float","min":60,"max":250,"decimals":1}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Shoelace sum","formula":"A = 0.5 |sum(x_i y_{i+1} - x_{i+1} y_i)|","calculation_template":"0.5 x |{{bx:f1}} x {{cy:f1}}|"},{"step_number":2,"title":"Result","result_template":"Area = {{_answer}} sq ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'With A at the origin, the coordinate (shoelace) area reduces to 0.5 x base x height = 0.5 x {{bx:f1}} x {{cy:f1}} = {{_answer}} sq ft.', 'acc00002-0000-0000-0000-000000000002', ARRAY['buildout','module-30','practice']::text[], true, 'buildout:m30');
  'eeee3050-0000-0000-0000-000000000004', 'Differential leveling — new point elevation (HI method)', 'Differential leveling — new point elevation (HI method)', 'Surveying Applications (Lab) — Leveling', 'HI reduction', 'numeric_input', 'easy', 'A benchmark has elevation {{bm:f2}} ft. A backsight of {{bs:f2}} ft is read on the benchmark, then a foresight of {{fs:f2}} ft is read on a new point. Compute the elevation of the new point (ft).', 'bm+bs-fs', '{"decimals":2,"unit":"ft","tolerance":0.005}', '[{"name":"bm","type":"float","min":80,"max":500,"decimals":2},{"name":"bs","type":"float","min":1,"max":9,"decimals":2},{"name":"fs","type":"float","min":1,"max":9,"decimals":2}]'::jsonb, '[{"name":"hi","formula":"bm+bs"}]'::jsonb, '[{"step_number":1,"title":"Height of instrument","formula":"HI = Elev + BS","calculation_template":"{{bm:f2}} + {{bs:f2}} = {{hi:f2}} ft"},{"step_number":2,"title":"New elevation","formula":"Elev = HI - FS","result_template":"{{hi:f2}} - {{fs:f2}} = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'HI = {{bm:f2}} + {{bs:f2}} = {{hi:f2}} ft; new elevation = HI - FS = {{hi:f2}} - {{fs:f2}} = {{_answer}} ft.', 'acc00002-0000-0000-0000-000000000002', ARRAY['buildout','module-30','practice']::text[], true, 'buildout:m30');
  'eeee3050-0000-0000-0000-000000000005', 'Slope distance reduced to horizontal via zenith angle', 'Slope distance reduced to horizontal via zenith angle', 'Surveying Applications (Lab) — EDM', 'Slope reduction', 'numeric_input', 'medium', 'A total station measures a slope distance of {{sd:f2}} ft at a zenith angle of {{z:f0}} deg. Compute the HORIZONTAL distance (ft).', 'sd*sin(toRad(z))', '{"decimals":2,"unit":"ft","tolerance":0.02}', '[{"name":"sd","type":"float","min":100,"max":600,"decimals":2},{"name":"z","type":"integer","min":80,"max":100}]'::jsonb, '[{"name":"vert","formula":"sd*cos(toRad(z))"}]'::jsonb, '[{"step_number":1,"title":"Horizontal from zenith","formula":"H = S sin(z)","calculation_template":"{{sd:f2}} x sin({{z:f0}} deg)"},{"step_number":2,"title":"Result","result_template":"Horizontal distance = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'Using the zenith angle, H = S sin(z) = {{sd:f2}} x sin({{z:f0}} deg) = {{_answer}} ft. The vertical component V = S cos(z) = {{vert:f2}} ft.', 'acc00002-0000-0000-0000-000000000002', ARRAY['buildout','module-30','practice']::text[], true, 'buildout:m30');
COMMIT;
SELECT 'm30 ACC SRVY 1335 — Land Surveying Applications (Lab): ' || (SELECT count(*) FROM lesson_blocks lb JOIN learning_lessons l ON l.id=lb.lesson_id WHERE l.module_id='acc00002-0000-0000-0000-000000000002') || ' blocks.' AS status;